/**
 * @summary Diff two analyses (SBOM comparison)
 */
export const getCreateDiffUrl = () => {
  return `/api/diff`;
};

export const createDiff = async (
  createDiffBody: CreateDiffBody,
  options?: RequestInit,
): Promise<SbomDiff> => {
  return customFetch<SbomDiff>(getCreateDiffUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(createDiffBody),
  });
};

export const getCreateDiffMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof createDiff>>,
    TError,
    { data: BodyType<CreateDiffBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof createDiff>>,
  TError,
  { data: BodyType<CreateDiffBody> },
  TContext
> => {
  const mutationKey = ["createDiff"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof createDiff>>,
    { data: BodyType<CreateDiffBody> }
  > = (props) => {
    const { data } = props ?? {};

    return createDiff(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type CreateDiffMutationResult = NonNullable<
  Awaited<ReturnType<typeof createDiff>>
>;
export type CreateDiffMutationBody = BodyType<CreateDiffBody>;
export type CreateDiffMutationError = ErrorType<unknown>;

/**
 * @summary Diff two analyses (SBOM comparison)
 */
export const useCreateDiff = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof createDiff>>,
    TError,
    { data: BodyType<CreateDiffBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof createDiff>>,
  TError,
  { data: BodyType<CreateDiffBody> },
  TContext
> => {
  return useMutation(getCreateDiffMutationOptions(options));
};
